INSERT INTO zones (city_id, zone_code, zone_code_slug, zone_name, description, max_height_ft, far, min_lot_size_sqft, max_impervious_cover_pct, setback_front_ft, setback_rear_ft, setback_side_ft, parking_requirement) VALUES ((SELECT id FROM cities WHERE slug = 'tampa'), 'RS-50', 'rs-50', 'Residential Single-Family 50', 'This district provides areas for primarily low-density single-family detached dwellings with smaller minimum lot size requirements, aiming to maintain neighborhood character.', NULL, NULL, 5000, NULL, 20, 7, 7, 'Accessory dwelling units greater than 600 square feet require 1 off-street parking space.') ON CONFLICT (city_id, zone_code_slug) DO UPDATE SET zone_name = excluded.zone_name, description = excluded.description, max_height_ft = excluded.max_height_ft, far = excluded.far, min_lot_size_sqft = excluded.min_lot_size_sqft, max_impervious_cover_pct = excluded.max_impervious_cover_pct, setback_front_ft = excluded.setback_front_ft, setback_rear_ft = excluded.setback_rear_ft, setback_side_ft = excluded.setback_side_ft, parking_requirement = excluded.parking_requirement;
INSERT INTO zone_permitted_uses (zone_id, permitted_use_id) SELECT z.id, pu.id FROM zones z, permitted_uses pu WHERE z.zone_code_slug = 'rs-50' AND z.city_id = (SELECT id FROM cities WHERE slug = 'tampa') AND pu.name IN ('Single-family detached dwelling', 'Accessory Dwelling Unit (ADU)') ON CONFLICT DO NOTHING;
INSERT INTO zones (city_id, zone_code, zone_code_slug, zone_name, description, max_height_ft, far, min_lot_size_sqft, max_impervious_cover_pct, setback_front_ft, setback_rear_ft, setback_side_ft, parking_requirement) VALUES ((SELECT id FROM cities WHERE slug = 'tampa'), 'RS-75', 'rs-75', 'Residential Single-Family 75', 'This district designates areas for single-family detached dwellings with specific lot size and setback requirements.', NULL, NULL, 7500, NULL, 20, 15, 12, 'Accessory dwelling units greater than 600 square feet require 1 off-street parking space.') ON CONFLICT (city_id, zone_code_slug) DO UPDATE SET zone_name = excluded.zone_name, description = excluded.description, max_height_ft = excluded.max_height_ft, far = excluded.far, min_lot_size_sqft = excluded.min_lot_size_sqft, max_impervious_cover_pct = excluded.max_impervious_cover_pct, setback_front_ft = excluded.setback_front_ft, setback_rear_ft = excluded.setback_rear_ft, setback_side_ft = excluded.setback_side_ft, parking_requirement = excluded.parking_requirement;
