INSERT INTO zones (city_id, zone_code, zone_code_slug, zone_name, description, max_height_ft, far, min_lot_size_sqft, max_impervious_cover_pct, setback_front_ft, setback_rear_ft, setback_side_ft, parking_requirement) VALUES ((SELECT id FROM cities WHERE slug = 'tampa'), 'RM-24', 'rm-24', 'Residential Multi-Family 24', 'This district is intended for multi-family residential developments, allowing for moderate to high-density housing.', NULL, NULL, NULL, NULL, 25, 20, 7, 'One (1) loading berth minimum for multiple family projects. Parking structures accessory to principal residential use are permitted if they meet area, height, bulk, and placement regulations.') ON CONFLICT (city_id, zone_code_slug) DO UPDATE SET zone_name = excluded.zone_name, description = excluded.description, max_height_ft = excluded.max_height_ft, far = excluded.far, min_lot_size_sqft = excluded.min_lot_size_sqft, max_impervious_cover_pct = excluded.max_impervious_cover_pct, setback_front_ft = excluded.setback_front_ft, setback_rear_ft = excluded.setback_rear_ft, setback_side_ft = excluded.setback_side_ft, parking_requirement = excluded.parking_requirement;
