INSERT INTO zones (city_id, zone_code, zone_code_slug, zone_name, description, max_height_ft, far, min_lot_size_sqft, max_impervious_cover_pct, setback_front_ft, setback_rear_ft, setback_side_ft, parking_requirement) VALUES ((SELECT id FROM cities WHERE slug = 'tampa'), 'CN', 'cn', 'Commercial Neighborhood', 'This district is intended for neighborhood-oriented commercial uses, with specific requirements for landscaping and setbacks when adjacent to residential areas.', NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'For non-residential development, 1 space per 2,500 square feet, with structures under 1,500 gross floor area not required to provide parking.') ON CONFLICT (city_id, zone_code_slug) DO UPDATE SET zone_name = excluded.zone_name, description = excluded.description, max_height_ft = excluded.max_height_ft, far = excluded.far, min_lot_size_sqft = excluded.min_lot_size_sqft, max_impervious_cover_pct = excluded.max_impervious_cover_pct, setback_front_ft = excluded.setback_front_ft, setback_rear_ft = excluded.setback_rear_ft, setback_side_ft = excluded.setback_side_ft, parking_requirement = excluded.parking_requirement;
