INSERT INTO zones (city_id, zone_code, zone_code_slug, zone_name, description, max_height_ft, far, min_lot_size_sqft, max_impervious_cover_pct, setback_front_ft, setback_rear_ft, setback_side_ft, parking_requirement) VALUES ((SELECT id FROM cities WHERE slug = 'tampa'), 'CG', 'cg', 'Commercial General', 'This district defines and controls major pedestrian-oriented shopping and business areas, with regulations that may include increased side setbacks for taller buildings.', NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'Most retail establishments require 1 parking space per 250 square feet of gross floor area; shopping centers require 4 spaces per 1,000 square feet of gross leasable area.') ON CONFLICT (city_id, zone_code_slug) DO UPDATE SET zone_name = excluded.zone_name, description = excluded.description, max_height_ft = excluded.max_height_ft, far = excluded.far, min_lot_size_sqft = excluded.min_lot_size_sqft, max_impervious_cover_pct = excluded.max_impervious_cover_pct, setback_front_ft = excluded.setback_front_ft, setback_rear_ft = excluded.setback_rear_ft, setback_side_ft = excluded.setback_side_ft, parking_requirement = excluded.parking_requirement;
