INSERT INTO zones (city_id, zone_code, zone_code_slug, zone_name, description, max_height_ft, far, min_lot_size_sqft, max_impervious_cover_pct, setback_front_ft, setback_rear_ft, setback_side_ft, parking_requirement) VALUES ((SELECT id FROM cities WHERE slug = 'tampa'), 'NMU-16', 'nmu-16', 'Neighborhood Mixed Use 16', 'This district allows for mixed-use development at a neighborhood scale, including residential, office, and commercial uses, within designated Urban Villages.', NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'Local governments must consider reducing parking for such developments. Mixed-use qualifying developments with surface or structured parking less than six stories may provide 20% greenspace.') ON CONFLICT (city_id, zone_code_slug) DO UPDATE SET zone_name = excluded.zone_name, description = excluded.description, max_height_ft = excluded.max_height_ft, far = excluded.far, min_lot_size_sqft = excluded.min_lot_size_sqft, max_impervious_cover_pct = excluded.max_impervious_cover_pct, setback_front_ft = excluded.setback_front_ft, setback_rear_ft = excluded.setback_rear_ft, setback_side_ft = excluded.setback_side_ft, parking_requirement = excluded.parking_requirement;
